    float mantissas[] = { 0.5f, 0.75f, 1.0f, -0.5f, -0.75f, -1.0f };
    int exponents[] = { 0, 1, 2, 5, 10, -5, -10 };

    for (int i = 0; i < 6; i++) {
        for (int j = 0; j < 7; j++) {
            emit(mantissas[i], exponents[j]);
        }
    }
}

