static void test_large_exp(void)
{
    float vals[] = { 0.5f, 1.0f, -1.0f, FLT_MAX };
    int exps[] = { 127, 126, -126, -127, 200, -200 };

    for (int i = 0; i < 4; i++) {
        for (int j = 0; j < 6; j++) {
            emit(vals[i], exps[j]);
        }
    }
}

