    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→static inline uint64_t d2u(double d)
    16→{
    17→    union { double d; uint64_t u; } x;
    18→    x.d = d;
    19→    return x.u;
    20→}
    21→
    22→static inline double u2d(uint64_t u)
    23→{
    24→    union { double d; uint64_t u; } x;
    25→    x.u = u;
    26→    return x.d;
    27→}
    28→
    29→static void emit(double x, double y)
    30→{
    31→    double r = hypot(x, y);
