    38→static void emit_u(uint64_t bits_x, uint64_t bits_y)
    39→{
    40→    emit(u2d(bits_x), u2d(bits_y));
    41→}
    42→
    43→/* ------------------------------------------------------------------ */
    44→/* Test points                                                         */
    45→/* ------------------------------------------------------------------ */
    46→
    47→/* 1. Special values */
    48→static void test_special(void)
    49→{
    50→    /* Zeros */
    51→    emit(0.0, 0.0);
    52→    emit(-0.0, 0.0);
    53→    emit(0.0, -0.0);
    54→
    55→    /* NaN */
    56→    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL); /* qNaN, 1.0 */
    57→    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL); /* 1.0, qNaN */
    58→    emit_u(0x7ff0000000000001ULL, 0x3ff0000000000000ULL); /* sNaN, 1.0 */
    59→
    60→    /* Infinity */
    61→    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL); /* +Inf, 1.0 */
    62→    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL); /* -Inf, 1.0 */
    63→    emit_u(0x3ff0000000000000ULL, 0x7ff0000000000000ULL); /* 1.0, +Inf */
    64→}
    65→
    66→/* 2. Tiny values */
    67→static void test_tiny(void)
    68→{
    69→    emit_u(0x0000000000000001ULL, 0x0000000000000001ULL); /* min denorm, min denorm */
    70→    emit_u(0x0008000000000000ULL, 0x0008000000000000ULL); /* mid denorm, mid denorm */
    71→    emit_u(0x000fffffffffffffULL, 0x000fffffffffffffULL); /* max denorm, max denorm */
    72→    emit(DBL_MIN, DBL_MIN);
    73→    emit(1.0e-150, 1.0e-150);
    74→    emit(1.0e-100, 1.0e-100);
