    78→static void test_known(void)
    79→{
    80→    /* 3-4-5 triple */
    81→    emit(3.0, 4.0);    /* sqrt(9+16) = 5 */
    82→    emit(4.0, 3.0);    /* sqrt(16+9) = 5 (commutative) */
    83→
    84→    /* 5-12-13 triple */
