/*
 * log1p() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly log1p   (test_log1p_opt.elf)
 *   2. Linked with toolchain's default log1p        (test_log1p_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifndef EN_PERF
static void emit(double x)
{
    double r = log1p(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros (log1p(0) = 0) */
    emit(0.0);
    emit(-0.0);

    /* NaN */
    emit_u(0x7ff8000000000000ULL); /* qNaN */
    emit_u(0x7ff0000000000001ULL); /* sNaN */
    emit_u(0xfff8000000000000ULL); /* -NaN */

    /* Infinity */
    emit_u(0x7ff0000000000000ULL); /* +Inf (log1p(Inf) = Inf) */
    emit_u(0xfff0000000000000ULL); /* -Inf (log1p(-Inf) = NaN) */

    /* Boundary: log1p(-1) = -Inf */
    emit_u(0xbff0000000000000ULL); /* -1.0 */
}

/* 2. Tiny values: log1p(x) ~ x when x is tiny */
static void test_tiny(void)
{
    emit_u(0x0000000000000001ULL); /* min denorm */
    emit_u(0x8000000000000001ULL);
    emit_u(0x0008000000000000ULL); /* mid denorm */
    emit_u(0x8008000000000000ULL);
    emit_u(0x000fffffffffffffULL); /* max denorm */
    emit_u(0x800fffffffffffffULL);
    emit(DBL_MIN);
    emit(-DBL_MIN);
    emit(1.0e-200);
    emit(-1.0e-200);
    emit(1.0e-100);
    emit(-1.0e-100);
}

/* 3. Known mathematical values */
static void test_known(void)
{
    emit(0.0);                      /* log1p(0) = 0 */
    emit(1.0);                      /* log1p(1) = log(2) */
    emit(2.718281828 - 1.0);        /* log1p(e-1) = 1 */
    emit(-0.5);                     /* log1p(-0.5) = log(0.5) */
    emit(0.5);                      /* log1p(0.5) = log(1.5) */
    emit(9.0);                      /* log1p(9) = log(10) */
    emit(-0.9);                     /* log1p(-0.9) = log(0.1) */
    emit(99.0);                     /* log1p(99) = log(100) */
}

/* 4. Large values */
static void test_large(void)
{
    double vals[] = {
        10.0, 100.0, 1000.0, 10000.0, 100000.0,
        1.0e50, 1.0e100, 1.0e150, 1.0e200, 1.0e300,
        DBL_MAX,
        -0.5, -0.9, -0.99, -0.999, -0.9999, -0.99999,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Critical near-zero region where log1p(x) ~ x */
static void test_quadrant(void)
{
    double tiny_vals[] = {
        1.0e-20, 5.0e-20, 1.0e-15, 5.0e-15,
        1.0e-10, 5.0e-10, 1.0e-5, 5.0e-5,
        1.0e-3, 1.0e-2,
        -1.0e-20, -5.0e-20, -1.0e-15, -5.0e-15,
        -1.0e-10, -5.0e-10, -1.0e-5, -5.0e-5,
        -1.0e-3, -1.0e-2,
    };
    int n = sizeof(tiny_vals) / sizeof(tiny_vals[0]);
    for (int i = 0; i < n; i++)
        emit(tiny_vals[i]);
}

/* 6. Worst-case near boundaries */
static void test_hard(void)
{
    double cases[] = {
        u2d(0x3ff0000000000000ULL), /* 1.0 exactly (log1p(1) = log(2)) */
        u2d(0x3ff0000000000001ULL), /* 1.0 + 1 ULP */
        u2d(0x3feffffffffffffULL), /* 1.0 - 1 ULP */
        u2d(0xbff0000000000000ULL), /* -1.0 exactly (log1p(-1) = -Inf) */
        u2d(0xbfeffffffffffffULL), /* -1.0 + 1 ULP */
        u2d(0xbff0000000000001ULL), /* -1.0 - 1 ULP */
        -0.999999, -0.99999, -0.9999,
        0.999999, 0.99999, 0.9999,
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++)
        emit(cases[i]);
}

/* 7. Sweep [-0.95, 100.0] in 200 steps */
static void test_sweep(void)
{
    double lo = -0.95;
    double hi = 100.0;
    int nsteps = 200;
    double step = (hi - lo) / (double)nsteps;

    /* [-0.95, 100.0] */
    for (int i = 0; i <= nsteps; i++)
        emit(lo + (double)i * step);

    /* [100.0, -0.95] (decreasing) */
    for (int i = 0; i <= nsteps; i++)
        emit(hi - (double)i * step);
}

/* 8. Sample [0, 0.1] every 2^47 ULP (~256 cases) */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3f847ae147ae147bULL, /* 0.01 */
        0x3f9eb851eb851eb8ULL, /* 0.03 */
        0x3fa999999999999aULL, /* 0.05 */
        0x3fb4cccccccccccdULL, /* 0.08 */
        0x3fb999999999999aULL, /* ~0.1 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i]);
}

/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    double lo = -0.9;
    double hi =  100.0;
    int n = 300;
    for (int i = 0; i < n; i++) {
        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
        emit(x);
    }
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(double x)
{
    volatile double acc = 0.0;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += log1p(x+i);
    stopPFM;
    readResult();
    printf("perf %016llx: %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u((double)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(1.0);
#else
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_quadrant();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}

/*
