    emit(0.5);      /* expm1(0.5) = sqrt(e)-1 */
    emit(-0.5);     /* expm1(-0.5) */
    emit(2.0);      /* expm1(2) = e^2-1 */
    emit(-2.0);     /* expm1(-2) */
    emit(10.0);     /* expm1(10) large positive */
}

/* 4. Overflow/underflow boundaries */
static void test_large(void)
{
    double vals[] = {
        -745.0,  /* deep underflow */
        -744.0,  /* near underflow boundary */
        -700.0,
        -100.0,
        100.0,
        700.0,   /* near overflow boundary */
        708.0,
        709.0,   /* overflow boundary */
        1000.0,  /* deep overflow */
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

